module shift_reg_16bit(
    input clk,
    input rst,
    input load,
    input sin,
    input [15:0] pdata,
    output sout,
    output [15:0] q
);

    reg [15:0] reset_reg;

    always @(posedge clk) begin
        if (rst) begin
            reset_reg <= 16'b0;
        end else if (load) begin
            reset_reg <= pdata;
        end else begin
            reset_reg <= {reset_reg[14:0], sin};
        end
    end

    assign sout = reset_reg[15];
    assign q = reset_reg;

endmodule
